var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"그리고 마지막 주의사항으로…","JPN":"そして最後の注意事項として……","ENG":"And lastly, one final precaution…","TWN":"最後一個注意事項…"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"헌혈이나 수혈은 함부로 하시면 안 됩니다. 혈액이 필요한 경우, 이 팔찌를 차고 계시면 도시관리국에서 도움을 드릴 거예요.","JPN":"献血や輸血は任意で行わないこと。血液が必要な場合、このブレスレットをしていれば都市管理局からサポートがあるはずです。","ENG":"You mustn't give or receive blood carelessly. If you ever need a transfusion, wear this band and the City Management will handle it for you.","TWN":"不要隨便捐血或輸血。如果需要血液，只要戴著這個手環，城市管理局就會協助你。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"저기. 제대로 듣고 계신 거 맞죠?","JPN":"あの、聞いていますか？","ENG":"Hey, are you listening to all this?","TWN":"先生，你有在聽嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…듣고 있네.","JPN":"……聞いているとも。","ENG":"…I hear you.","TWN":"…有在聽。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"방금 말한 열 가지 주의사항도 새겨두도록 하지.","JPN":"先程言われた10個の注意事項もしっかり覚えておくとしよう。","ENG":"I shall keep in mind the ten other points you just listed.","TWN":"剛才說的十個注意事項，我也會牢記在心。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"건강에 문제가 있는 것 같으면 언제든 저희 민원 부서로 편하게 연락 주세요.","JPN":"健康に異常を感じましたら、いつでも担当部署にご連絡ください。","ENG":"If you ever feel unwell, please don't hesitate to reach out to our civil office.","TWN":"要是身體有哪裡不舒服，歡迎隨時找我們。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"기억 소거의 후유증은 거의 없는 편이라고 하지만, 혹시 모르니까요.","JPN":"記憶消去の後遺症はほぼないと言われていますが、注意して損することはありませんから。","ENG":"There are almost no side effects from memory erasure, but you never know.","TWN":"雖然刪除記憶後沒什麼後遺症，但還是提醒一下。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"기억 소거…","JPN":"記憶消去……","ENG":"Memory erasure…","TWN":"刪除記憶…"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그래. 관리국을 떠나는 조건으로 내 기억을 지우기로 했었지.","JPN":"そうか。管理局を去る条件として、自分の記憶を消すことにしたのであったな。","ENG":"Right. That was the condition for leaving the Administration.","TWN":"沒錯，我離開管理局的條件，就是要刪除我的記憶。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"정확히는 관리국에 근무하실 적의 기억만 사라진 겁니다.","JPN":"正確には、管理局に勤めていた間の記憶だけですね。","ENG":"Technically speaking, only your memories from your time in the Administration are gone.","TWN":"準確地說，只有刪除你在管理局工作時的記憶。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"함께 일한 동료의 이름이나 얼굴을 기억하거나 한때 익숙했던 것에 대한 기시감 정도는 느낄 수 있겠지만, 시술에 이상이 있다는 뜻은 아니니 너무 걱정 마시고요.","JPN":"一緒に働いていた同僚の名前や顔を思い出したり、見慣れていたものに対する既視感は残るかもしれませんが、施術に問題があったわけではありませんので、ご心配なく。","ENG":"You may still feel a vague sense of familiarity if you run into an old colleague or something familiar, but that's normal. Nothing to worry about.","TWN":"你可能會記得一起共事過的夥伴名字或臉孔，或是對曾經熟悉的事物產生既視感，但這並不代表手術有問題，所以不用太擔心。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이해했네.","JPN":"理解した。","ENG":"Understood.","TWN":"我明白了。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"현 시간 부로 당신의 신원은 관리국에 귀속되지 않습니다. 퇴사 절차는 끝났어요.","JPN":"現時刻をもって、あなたの身元は管理局の所管外となります。これで退職手続きは完了しました。","ENG":"As of this moment, you are no longer bound to the Administration. Your discharge is complete.","TWN":"從現在起，你的身份不再屬於管理局。離職手續都已經跑完了。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"고마웠소. 여러 모로.","JPN":"色々と感謝する。","ENG":"My thanks. For all of it.","TWN":"謝謝你，還提醒我這麼多事。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"감사는 오히려 저희 같은 사람들이 해야죠.","JPN":"感謝するのはむしろ私たちの方です。","ENG":"We're the ones who should thank you.","TWN":"應該謝謝的反而是我們。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"전 내부 사정을 잘 모르는 관외 직원일 뿐이지만…","JPN":"私は内部の事情に詳しくない外部職員ですが……","ENG":"I'm just a staff, so I don't know much about internal matters but…","TWN":"我雖然只是個小員工，不清楚解內部情況…"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"관리실패를 겪고 살아남은 관리국 분들은 모두 존중 받을 만한 분이라 생각하거든요.","JPN":"管理失敗を経験してなお生き残った管理局の方々は、皆尊敬に値する方々だと思っています。","ENG":"I believe anyone who survived the Administration Failure deserves respect.","TWN":"但我認為經歷管理失敗後倖存下來的管理局人員，都值得尊敬。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"관리실패…?","JPN":"管理失敗……？","ENG":"Administration Failure…?","TWN":"管理失敗…？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"아, 제가 쓸데없는 소릴 했네요. 시술 직후엔 복잡한 생각을 피하라고 했는데.","JPN":"あ、余計なことを口走ってしまいましたね。施術直後は複雑なことを考えないようにと言われているのに。","ENG":"Ah, forget I said that. You're not supposed to dwell on anything complicated right after the procedure.","TWN":"抱歉，我在胡說什麼。明明說過手術後要避免複雜的思考。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"이건 챔버로 가는 항공 탑승권입니다.","JPN":"こちらチェンバー行きの航空券です。","ENG":"This is your ticket to Chamber.","TWN":"這是前往強巴的機票。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"도착하면 현지 기업의 연구원 분들이 기다리고 계실 거예요.","JPN":"着きましたら、現地企業の研究員の方々が迎えに来ていると思います。","ENG":"Once you arrive, researchers from a local company will be waiting for you.","TWN":"抵達後，會有當地企業的研究員等著你。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"챔버? 고향으로 돌아가는 게 절차가 아니었나? 내가 살던 곳은 그곳이 아닐 텐데.","JPN":"チェンバー？　マニュアルによれば、次は故郷に帰るのではなかったか？　某が住んでいた場所はそこではないはずだが。","ENG":"Chamber? Wasn't I supposed to return home? That's not where I lived.","TWN":"強巴？按照規定不是應該回故鄉嗎？我原本住的地方應該不是那裡。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"맞아요. 당신의 예전 거주지는 현재… KS-7이라 불리는 관리국 관할지로 변했죠.","JPN":"そうですね。あなたの居住地だった場所は現在……KS-7と呼ばれる管理局管轄地になっています。","ENG":"True. Your old home is now… under the Administration's jurisdiction called KS-7.","TWN":"沒錯。你以前居住的地方，現在…稱為KS-7， 是由管理局管轄的地方。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"거긴 평범한 시골이던 과거와 달리, 지금은 사람이 살 수 없는 아주 위험한 침식지대예요.","JPN":"普通の田舎町だった昔と違い、今は人が住めない危険な侵食地帯です。","ENG":"It's no longer the quiet countryside it used to be. It's an uninhabitable, dangerous Corrupted Area now.","TWN":"那裡已經不再是過去的純樸鄉村，現在是個無法居住、非常危險的侵蝕地帶。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"대신 챔버엔 당신 같은 인재를 필요로 하는 기업과 안전한 집이 있거든요.","JPN":"ですが、チェンバーにはあなたのような人材を求めている企業と、安全な住宅があるのです。","ENG":"But Chamber has safe housing and companies that need talent like yours.","TWN":"但強巴有需要你這種人才的企業和安全的家。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…그렇구려.","JPN":"……そうか。","ENG":"…I see.","TWN":"…原來如此。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"안전을 위해 고향은 돌아가지 못하게 된 건가.","JPN":"身の安全のため、故郷には戻れぬようになってしまったのか。","ENG":"So, I can't go back for safety's sake.","TWN":"基於安全的緣故，我不能回到故鄉嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"챔버로 가겠소.","JPN":"チェンバーに行こう。","ENG":"Chamber it is, then.","TWN":"我會去強巴。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};